import React from "react";
import { Link } from "react-router-dom";
import "./Home.css"; // optional styling

export default function Home() {
  return (
    <div className="home">
      <section className="hero">
        <h1>Find Your Perfect Getaway 🏖️</h1>
        <p>Book amazing stays and experiences around the world.</p>
        <Link to="/booking-confirmation">
          <button className="book-btn">Book Now</button>
        </Link>
      </section>

      <section className="gallery">
        <img src="https://source.unsplash.com/600x400/?beach" alt="Beach" />
        <img src="https://source.unsplash.com/600x400/?mountain" alt="Mountain" />
        <img src="https://source.unsplash.com/600x400/?hotel" alt="Hotel" />
      </section>
    </div>
  );
}
